{"report_type": "HTML", "html": "<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<style>
  @page { size: A4 landscape; margin: 10mm 12mm 8mm 12mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 8.5pt; color: #1a1a2e; background: #fff; }
  .page { max-width: 100%; margin: 0; padding: 0; }

  .hotel-logo { max-height: 52px; max-width: 95px; }
  .logo-box { display: inline-block; width: 44px; height: 44px; background: #1a1a2e; color: #fff; font-size: 15pt; font-weight: 700; text-align: center; line-height: 44px; border-radius: 5px; }
  .hotel-name { font-size: 13pt; font-weight: 700; color: #1a1a2e; }
  .hotel-sub { font-size: 7pt; color: #6b7280; margin-top: 2px; line-height: 1.5; }
  .doc-title { font-size: 12pt; font-weight: 700; color: #1a1a2e; }
  .doc-subtitle { font-size: 7pt; color: #6b7280; text-transform: uppercase; letter-spacing: 0.8px; margin-top: 2px; }
  .doc-ref { font-size: 8pt; color: #6b7280; margin-top: 6px; line-height: 1.7; }
  .doc-ref strong { color: #374151; }
  .header-divider { border: none; border-top: 2px solid #1a1a2e; margin: 12px 0 14px; }

  .pill { display: inline-block; padding: 2px 9px; border-radius: 10px; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.4px; margin-right: 5px; border: 1px solid #d1d5db; background: #f9fafb; color: #374151; }
  .pills-row { margin-bottom: 12px; }

  .section-title { font-size: 7.5pt; font-weight: 700; color: #1a1a2e; text-transform: uppercase; letter-spacing: 0.6px; background: #f1f3f8; border-left: 3px solid #1a1a2e; border-bottom: 1px solid #d1d5db; padding: 5px 9px; margin-top: 14px; margin-bottom: 8px; }

  .info-table { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
  .info-table td { padding: 4px 8px; font-size: 8.5pt; border-bottom: 1px solid #f1f5f9; vertical-align: middle; white-space: nowrap; }
  .info-table tr:last-child td { border-bottom: none; }
  .info-key { width: 14%; color: #1a1a2e; font-weight: 700; }
  .info-val { width: 19%; color: #1a1a2e; }

  .stats-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
  .stats-table td { border: 1px solid #e5e7eb; padding: 5px 8px; text-align: center; }
  .s-label { font-size: 6.5pt; color: #9ca3af; display: block; text-transform: uppercase; letter-spacing: 0.4px; }
  .s-value { font-size: 11pt; font-weight: 700; color: #1a1a2e; display: block; margin-top: 2px; }
  .s-value.green { color: #15803d; }
  .s-value.red { color: #dc2626; }
  .s-value.amber { color: #d97706; }
  .s-value.blue { color: #1d4ed8; }

  .panel-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
  .panel-table td { vertical-align: top; padding: 0 6px 0 0; }
  .panel-table td:last-child { padding-right: 0; }
  .panel { border: 1px solid #e5e7eb; padding: 8px; background: #fff; }
  .panel-title { font-size: 7.5pt; font-weight: 700; color: #1a1a2e; text-transform: uppercase; letter-spacing: 0.4px; margin-bottom: 6px; border-bottom: 2px solid #1a1a2e; padding-bottom: 4px; }
  .mini-table { width: 100%; border-collapse: collapse; font-size: 8pt; }
  .mini-table thead th { background: #f1f3f8; color: #1a1a2e; padding: 4px 6px; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; text-align: left; border-bottom: 2px solid #1a1a2e; }
  .mini-table thead th.num { text-align: right; }
  .mini-table td { padding: 4px 6px; border-bottom: 1px solid #f1f5f9; }
  .mini-table tr:last-child td { border-bottom: none; }
  .mini-table td.num { text-align: right; }

  .data-table { width: 100%; border-collapse: collapse; font-size: 7.5pt; margin-bottom: 4px; }
  .data-table thead tr { background: #f1f3f8; color: #1a1a2e; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th { padding: 5px 5px; text-align: left; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; letter-spacing: 0.3px; white-space: nowrap; border-bottom: 2px solid #1a1a2e; }
  .data-table thead th.num { text-align: right; }
  .data-table thead th.ctr { text-align: center; }
  .data-table tbody tr:nth-child(even) { background: #f9fafb; }
  .data-table tbody td { padding: 5px 5px; border-bottom: 1px solid #f1f5f9; color: #374151; vertical-align: middle; }
  .data-table tbody td.num { text-align: right; }
  .data-table tbody td.ctr { text-align: center; }
  .data-table tfoot tr { border-top: 2px solid #1a1a2e; background: #f1f3f8; color: #1a1a2e; }
  .data-table tfoot td { padding: 6px 5px; font-weight: 700; color: #1a1a2e; font-size: 8pt; }
  .data-table tfoot td.num { text-align: right; }

  .badge { display: inline-block; padding: 1px 6px; border-radius: 8px; font-size: 6.5pt; font-weight: 700; text-transform: uppercase; white-space: nowrap; }
  .badge-released    { background: #dcfce7; color: #166534; border: 1px solid #bbf7d0; }
  .badge-inspected   { background: #dbeafe; color: #1d4ed8; border: 1px solid #bfdbfe; }
  .badge-cleaned     { background: #ede9fe; color: #5b21b6; border: 1px solid #ddd6fe; }
  .badge-pending     { background: #fef3c7; color: #b45309; border: 1px solid #fde68a; }
  .badge-maintenance { background: #fee2e2; color: #b91c1c; border: 1px solid #fecaca; }
  .badge-muted       { background: #f3f4f6; color: #4b5563; border: 1px solid #e5e7eb; }
  .ref { font-family: monospace; background: #f3f4f6; color: #374151; padding: 1px 4px; border-radius: 3px; font-size: 7pt; white-space: nowrap; }
  .good { color: #15803d; font-weight: 700; }
  .warn { color: #d97706; font-weight: 700; }
  .bad  { color: #dc2626; font-weight: 700; }

  .footer-divider { border: none; border-top: 1px solid #e5e7eb; margin: 14px 0 8px; }
  .footer-note { font-size: 7pt; color: #9ca3af; line-height: 1.7; }
  .footer-company { font-size: 9pt; font-weight: 700; color: #1a1a2e; }
  .footer-date { font-size: 7pt; color: #9ca3af; margin-top: 2px; }
  .sig-line { margin-top: 14px; border-top: 1px solid #e5e7eb; padding-top: 5px; font-size: 7pt; color: #9ca3af; text-align: center; }
</style>
</head>
<body>
<div class="page">

  <!-- HEADER -->
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="55%" valign="top">
        <table cellpadding="0" cellspacing="0">
          <tr>
            <td style="padding-right:10px;" valign="middle">
              {% if hotel_logo %}
                <img src="{{ hotel_logo }}" alt="{{ company }}" class="hotel-logo" />
              {% else %}
                <div class="logo-box">{{ (company or 'H')[:1] }}</div>
              {% endif %}
            </td>
            <td valign="middle">
              <div class="hotel-name">{{ company }}</div>
              <div class="hotel-sub">
                {% if hotel_tagline %}{{ hotel_tagline }}<br>{% endif %}
                {% if hotel_address %}{{ hotel_address }}<br>{% endif %}
                {% if hotel_phone %}{{ hotel_phone }}{% if hotel_email %} &middot; {% endif %}{% endif %}
                {% if hotel_email %}{{ hotel_email }}{% endif %}
              </div>
            </td>
          </tr>
        </table>
      </td>
      <td valign="top" align="right">
        <div class="doc-title">Housekeeping Productivity</div>
        <div class="doc-subtitle">Room Cleaning &amp; Inspection Report</div>
        <div class="doc-ref">
          <strong>Period:</strong> {{ filters.date_from }} &ndash; {{ filters.date_to }}<br>
          <strong>Generated:</strong> {{ generated_at }}<br>
          <strong>Prepared By:</strong> {{ prepared_by }}
        </div>
      </td>
    </tr>
  </table>
  <hr class="header-divider" />

  <!-- PILLS -->
  <div class="pills-row">
    <span class="pill">{{ filters.date_from }} &ndash; {{ filters.date_to }}</span>
    {% if filters.housekeeper and filters.housekeeper != 'All Housekeepers' %}<span class="pill">{{ filters.housekeeper }}</span>{% endif %}
    {% if filters.floor and filters.floor != 'All Floors' %}<span class="pill">{{ filters.floor }}</span>{% endif %}
    {% if filters.status and filters.status != 'All Statuses' %}<span class="pill">{{ filters.status }}</span>{% endif %}
  </div>

  <!-- FILTERS -->
  <div class="section-title">Report Filters</div>
  <table class="info-table" cellpadding="0" cellspacing="0">
    <colgroup>
      <col style="width:14%" /><col style="width:19%" />
      <col style="width:14%" /><col style="width:19%" />
      <col style="width:14%" /><col style="width:19%" />
    </colgroup>
    <tr>
      <td class="info-key">Date From</td><td class="info-val">{{ filters.date_from }}</td>
      <td class="info-key">Date To</td><td class="info-val">{{ filters.date_to }}</td>
      <td class="info-key">Housekeeper</td><td class="info-val">{{ filters.housekeeper or 'All Housekeepers' }}</td>
    </tr>
    <tr>
      <td class="info-key">Floor</td><td class="info-val">{{ filters.floor or 'All Floors' }}</td>
      <td class="info-key">Status</td><td class="info-val">{{ filters.status or 'All Statuses' }}</td>
      <td class="info-key">Search</td><td class="info-val">{{ filters.search or '&mdash;' }}</td>
    </tr>
  </table>

  <!-- SUMMARY -->
  <div class="section-title">Summary</div>
  <table class="stats-table" cellpadding="0" cellspacing="0">
    <tr>
      <td><span class="s-label">Rooms Assigned</span><span class="s-value">{{ summary.rooms_assigned or 0 }}</span></td>
      <td><span class="s-label">Rooms Cleaned</span><span class="s-value green">{{ summary.rooms_cleaned or 0 }}</span></td>
      <td><span class="s-label">Rooms Inspected</span><span class="s-value blue">{{ summary.rooms_inspected or 0 }}</span></td>
      <td><span class="s-label">Avg Cleaning Time</span><span class="s-value">{{ summary.avg_cleaning_time or 0 }}m</span></td>
      <td><span class="s-label">Guest Requests</span><span class="s-value amber">{{ summary.guest_requests or 0 }}</span></td>
      <td><span class="s-label">Maintenance Issues</span><span class="s-value red">{{ summary.maintenance_issues or 0 }}</span></td>
    </tr>
  </table>

  <!-- BREAKDOWNS -->
  <div class="section-title">Breakdowns</div>
  <table class="panel-table" cellpadding="0" cellspacing="0">
    <tr>
      <td width="25%">
        <div class="panel">
          <div class="panel-title">Room Status Distribution</div>
          <table class="mini-table" cellpadding="0" cellspacing="0">
            <thead><tr><th>Status</th><th class="num">Count</th></tr></thead>
            <tbody>
              {% for row in status_breakdown %}
              <tr>
                <td>
                  {% set s = row.status or '' %}
                  {% if s in ['Released', 'Completed'] %}<span class="badge badge-released">{{ s }}</span>
                  {% elif s == 'Inspected' %}<span class="badge badge-inspected">{{ s }}</span>
                  {% elif s == 'Cleaned' %}<span class="badge badge-cleaned">{{ s }}</span>
                  {% elif s in ['Pending', 'Open'] %}<span class="badge badge-pending">{{ s }}</span>
                  {% elif s == 'Maintenance' %}<span class="badge badge-maintenance">{{ s }}</span>
                  {% else %}<span class="badge badge-muted">{{ s or 'Unknown' }}</span>{% endif %}
                </td>
                <td class="num" style="font-weight:700;">{{ row.count or 0 }}</td>
              </tr>
              {% else %}
              <tr><td colspan="2" style="color:#9ca3af;font-style:italic;padding:8px 0;">No data.</td></tr>
              {% endfor %}
            </tbody>
          </table>
        </div>
      </td>
      <td width="40%" style="padding-left:6px;">
        <div class="panel">
          <div class="panel-title">Housekeeper Productivity</div>
          <table class="mini-table" cellpadding="0" cellspacing="0">
            <thead><tr><th>Housekeeper</th><th class="num">Assigned</th><th class="num">Cleaned</th><th class="num">Avg Time</th><th class="num">Requests</th><th class="num">Score</th></tr></thead>
            <tbody>
              {% for p in housekeeper_performance %}
              <tr>
                <td style="font-weight:600;">{{ p.housekeeper or 'Unknown' }}</td>
                <td class="num">{{ p.assigned or 0 }}</td>
                <td class="num">{{ p.cleaned or 0 }}</td>
                <td class="num">{{ p.avg_time or 0 }}m</td>
                <td class="num">{{ p.requests or 0 }}</td>
                <td class="num {% if (p.score or 0) >= 80 %}good{% elif (p.score or 0) >= 50 %}warn{% else %}bad{% endif %}">{{ p.score or 0 }}%</td>
              </tr>
              {% else %}
              <tr><td colspan="6" style="color:#9ca3af;font-style:italic;padding:8px 0;">No data.</td></tr>
              {% endfor %}
            </tbody>
          </table>
        </div>
      </td>
      <td width="18%" style="padding-left:6px;">
        <div class="panel">
          <div class="panel-title">Floor Performance</div>
          <table class="mini-table" cellpadding="0" cellspacing="0">
            <thead><tr><th>Floor</th><th class="num">Done</th><th class="num">%</th></tr></thead>
            <tbody>
              {% for f in floor_performance %}
              <tr>
                <td style="font-weight:600;">{{ f.floor or 'Unknown' }}</td>
                <td class="num">{{ f.cleaned or 0 }}/{{ f.assigned or 0 }}</td>
                <td class="num {% if (f.completion or 0) >= 80 %}good{% elif (f.completion or 0) >= 50 %}warn{% else %}bad{% endif %}">{{ f.completion or 0 }}%</td>
              </tr>
              {% else %}
              <tr><td colspan="3" style="color:#9ca3af;font-style:italic;padding:8px 0;">No data.</td></tr>
              {% endfor %}
            </tbody>
          </table>
        </div>
      </td>
      <td width="17%" style="padding-left:6px;padding-right:0;">
        <div class="panel">
          <div class="panel-title">Inspection Summary</div>
          <table class="mini-table" cellpadding="0" cellspacing="0">
            <thead><tr><th>Inspector</th><th class="num">&#10003;</th><th class="num">&#10007;</th></tr></thead>
            <tbody>
              {% for i in inspector_summary %}
              <tr>
                <td style="font-weight:600;">{{ i.inspector or 'Unknown' }}</td>
                <td class="num good">{{ i.released or 0 }}</td>
                <td class="num bad">{{ i.rejected or 0 }}</td>
              </tr>
              {% else %}
              <tr><td colspan="3" style="color:#9ca3af;font-style:italic;padding:8px 0;">No data.</td></tr>
              {% endfor %}
            </tbody>
          </table>
        </div>
      </td>
    </tr>
  </table>

  <!-- DETAILED LOG -->
  <div class="section-title">Detailed Room Cleaning Log &mdash; {{ rows | length }} record(s)</div>
  {% if rows %}
  <table class="data-table" cellpadding="0" cellspacing="0">
    <thead>
      <tr>
        <th class="ctr">#</th><th>ID</th><th>Room</th><th>Floor</th>
        <th>Housekeeper</th><th>Start</th><th>End</th>
        <th class="num">Duration</th><th>Inspector</th>
        <th class="num">Requests</th><th>Issue</th><th>Status</th>
      </tr>
    </thead>
    <tbody>
      {% for room in rows %}
      <tr>
        <td class="ctr" style="color:#9ca3af;">{{ loop.index }}</td>
        <td><span class="ref">{{ room.id or '&mdash;' }}</span></td>
        <td style="font-weight:700;">{{ room.room or '&mdash;' }}</td>
        <td style="color:#6b7280;">{{ room.floor or '&mdash;' }}</td>
        <td style="font-weight:600;">{{ room.housekeeper or 'Unassigned' }}</td>
        <td style="color:#6b7280;font-size:7pt;">{{ room.start_time or '&mdash;' }}</td>
        <td style="color:#6b7280;font-size:7pt;">{{ room.end_time or '&mdash;' }}</td>
        <td class="num" style="font-weight:700;">{{ room.duration or 0 }}m</td>
        <td style="color:#6b7280;">{{ room.inspector or '&mdash;' }}</td>
        <td class="num">{{ room.guest_requests or 0 }}</td>
        <td style="color:#6b7280;font-size:7pt;">{{ room.issue or 'None' }}</td>
        <td>
          {% set s = room.status or '' %}
          {% if s in ['Released', 'Completed'] %}<span class="badge badge-released">{{ s }}</span>
          {% elif s == 'Inspected' %}<span class="badge badge-inspected">{{ s }}</span>
          {% elif s == 'Cleaned' %}<span class="badge badge-cleaned">{{ s }}</span>
          {% elif s in ['Pending', 'Open'] %}<span class="badge badge-pending">{{ s }}</span>
          {% elif s in ['Working'] %}<span class="badge badge-inspected">Working</span>
          {% elif s == 'Maintenance' %}<span class="badge badge-maintenance">Maintenance</span>
          {% else %}<span class="badge badge-muted">{{ s or '&mdash;' }}</span>{% endif %}
        </td>
      </tr>
      {% endfor %}
    </tbody>
    <tfoot>
      <tr>
        <td colspan="7" style="text-align:right;text-transform:uppercase;letter-spacing:0.5px;">Grand Total</td>
        <td class="num">{{ totals.duration or 0 }}m</td>
        <td></td>
        <td class="num">{{ totals.guest_requests or 0 }}</td>
        <td colspan="2"></td>
      </tr>
    </tfoot>
  </table>
  {% else %}
  <p style="padding:16px;text-align:center;color:#9ca3af;font-size:8.5pt;border:1px dashed #e5e7eb;">No housekeeping records found for the selected filters.</p>
  {% endif %}

  <!-- FOOTER -->
  <hr class="footer-divider" />
  <table width="100%" cellpadding="0" cellspacing="0">
    <tr>
      <td width="60%" valign="bottom">
        <div class="footer-note">
          This report is generated by the {{ company }} Property Management System.<br>
          Housekeeping note: Monitor room turnaround time, inspection failures, pending rooms, guest requests and maintenance reports.<br>
          <strong style="color:#374151;">Period: {{ filters.date_from }} to {{ filters.date_to }}</strong>
        </div>
      </td>
      <td valign="bottom" align="right">
        <div class="footer-company">{{ company }}</div>
        <div class="footer-date">{{ generated_at }}</div>
        <div class="sig-line">Authorised Signature</div>
      </td>
    </tr>
  </table>

</div>
</body>
</html>"}
